  # Record type AuthenticatedProofBundleVerificationRecord
class AuthenticatedProofBundleVerificationRecord
  attr_reader :valid, :envelope, :proof, :proof_error

  def initialize(valid:, envelope:, proof:, proof_error:)
    @valid = valid
    @envelope = envelope
    @proof = proof
    @proof_error = proof_error
  end

  def ==(other)
    if @valid != other.valid
      return false
    end
    if @envelope != other.envelope
      return false
    end
    if @proof != other.proof
      return false
    end
    if @proof_error != other.proof_error
      return false
    end

    true
  end
end

  # Record type AuthenticatedProofEnvelopeRecord
class AuthenticatedProofEnvelopeRecord
  attr_reader :algorithm, :key_id, :proof_bundle, :context, :issued_at_millis, :expires_at_millis, :nonce, :signature

  def initialize(algorithm:, key_id:, proof_bundle:, context:, issued_at_millis:, expires_at_millis:, nonce:, signature:)
    @algorithm = algorithm
    @key_id = key_id
